package com.mnu.exan01;
// 제어문 (if(), switch ~ case)
public class Exam_01 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a = 4;
		int b = 7;
		int c = a & b; // bit and
		int d = a | b; // bit or
		int e = a ^ b; // bit xor
		int f = ~ a; // bit not
		
		System.out.println("c = " + c);
		System.out.println("d = " + d);
		System.out.println("e = " + e);
		System.out.println("f = " + f);
	}

}
